--------------------------------------------------------------------------------
-- Language: en_US
insert or replace into EnglishText
    (Tag,                                                     Text)
values
    ("LOC_BUILDING_PETRA_NAME",                               "Al-Khazneh"),
    ("LOC_BUILDING_GREAT_BATH_DESCRIPTION",                   "Aqueduct district buildings can be purchased with [ICON_Faith] Faith. +50% Yields from Aqueduct district buildings.[NEWLINE][NEWLINE]The Floodplains tiles along the river containing the Great Bath are now immune to Flood damage (though [ICON_FOOD] Food and [ICON_PRODUCTION] Production bonuses from flooding drop by 50%). Floodplains tiles belonging to this city gain +1 [ICON_FAITH] Faith for each time Flood damage is mitigated.[NEWLINE][NEWLINE]Must be built on Floodplains tiles."),
    ("LOC_BUILDING_MEENAKSHI_TEMPLE_DESCRIPTION",             "Grants 2 Gurus. Districts with Citizen Slot in the city which has Holy Site receive +1 Citizen Slot, citizens in these districts provide +1 [ICON_FOOD] Food, +1 [ICON_CULTURE] Culture, +1 [ICON_FAITH] Faith and -2 [ICON_GOLD] Gold. The city which has Holy Site gain +2 [ICON_HOUSING] Housing. [ICON_GreatWork_SCULPTURE] Art Great Works provide +50% [ICON_TOURISM] Tourism in the City which has Holy Site. [NEWLINE][NEWLINE]Must be built adjacent to a Holy Site and you must have founded a Religion."), --Holy Site provides +1 [ICON_Food] Food 
    ("LOC_BUILDING_PANAMA_CANAL_DESCRIPTION",                 "1 free [Icon_GreatMerchant] Great Merchant appears near the city where the wonder was built. Upon completion 1 or 2 adjacent Canal districts are automatically constructed. The Canal wonder tile can now be crossed by naval units. [ICON_TradeRoute] Trade Routes traveling through it can multiply the [ICON_Gold] Gold they get from districts at their destination.[NEWLINE][NEWLINE]Must be built on a flat land tile where there are two adjacent tiles directly across the build tile from one another that meet the following criteria: one adjacent tile must be able to legally hold a Canal district connecting into the Panama Canal construction tile; the other must be either a city, a water tile, or be another tile that can hold a connecting Canal."),
    ("LOC_BUILDING_OXFORD_UNIVERSITY_DESCRIPTION",            "+20% [ICON_Science] Science in this city. Awards 2 freely-chosen free technologies when completed (to choose the Technology to be awarded, please click on the Technology icon on the Tech tree). Must be built on flat land adjacent to a Campus district with a University."),
	("LOC_UNCLOCK_FREE_TECH",            					  "Unlock this Technology.[NEWLINE]Can be used {1_Amount} more {1_Num : plural 1?time; other?times;}"),
    ("LOC_BUILDING_KILWA_KISIWANI_DESCRIPTION",               "+3 [ICON_ENVOY] Envoys when built. When you are the Suzerain of a City-State this city receives a +15% boost to the Type bonuses provided by that City-State. If you are the Suzerain to 2 or more City-States of that type this city receives an additional +15% boost to the Type bonuses provided by those City-States. [NEWLINE][NEWLINE]Must be built on a flat tile adjacent to Shallow Sea."),
    ("LOC_BUILDING_TERRACOTTA_ARMY_DESCRIPTION",              "Grants 1 promotion level to all current units. +1 Military policy slot. [NEWLINE][NEWLINE]Must be built on flat Grassland or Plains adjacent to an Encampment district with a Tier 1 building."),
    ("LOC_BUILDING_RUHR_VALLEY_DESCRIPTION",                  "Provides 6 [ICON_RESOURCE_COAL] Coal per turn. +15% [ICON_Production] Production in this city. Each city with a Factory or Electronics Factory +5% [ICON_Production] Production and +10% accumulation rate for [ICON_GREATENGINEER] Great Engineer Points. [NEWLINE][NEWLINE]International [ICON_TradeRoute] Trade Route to this city provides +3 [ICON_Production] Production for both sides. Domestic [ICON_TradeRoute] Trade Route to this City provides +6 [ICON_Production] Production. [NEWLINE][NEWLINE]Must be built adjacent to an Industrial Zone district with Tier 2 building, and next to a River."),
    ("LOC_BUILDING_SYDNEY_OPERA_HOUSE_DESCRIPTION",           "Grants 1 free [ICON_GreatMusician] Great Musician. Great works and Wonders provide +100% [Icon_Tourism] Tourism (extra 100% [Icon_Tourism] Tourism for [ICON_GreatWork_MUSIC] Music) if this city has [ICON_Governor] Governor established and is founded by you. Provide [ICON_GOLD] Gold equal to half of the [Icon_Tourism] Tourism every turn. [NEWLINE][NEWLINE]Must be built on the Shallow Sea, adjacent to land and a Harbor district."),
    ("LOC_BUILDING_HERMITAGE_DESCRIPTION",                    "Art Great Works provide +200% [ICON_TOURISM] Tourism in the City. When [ICON_GreatArtist] Great Artist created, gain all kinds of [ICON_GreatPerson] Great Person Points equal to 15% of next [ICON_GreatArtist] Great Artist's cost."),
    ("LOC_NOTIFIER_HERMITAGE_GPP",                            "{1_Amount}Great Person Points Gained from Hermitage."),
    ("LOC_BUILDING_HERMITAGE_QUOTE",                          "Real museums are places where Time is transformed into Space.[NEWLINE]- Orhan Pamuk, The Museum of Innocence"),
    ("LOC_BUILDING_FORBIDDEN_CITY_DESCRIPTION",               "+1 Wildcard policy slot. [NEWLINE][NEWLINE]Must be built on flat land adjacent to the City Center."),
    ("LOC_BUILDING_PETRA_DESCRIPTION",                        "+3 [ICON_Food] Food, +2 [ICON_Gold] Gold, and +1 [ICON_Production] Production to all non-Floodplains Desert tiles within 5 tiles. Must be built on Desert tiles (including Mountain and Floodplains)."),
    ("LOC_BUILDING_ST_BASILS_CATHEDRAL_DESCRIPTION",          "Each wonder in this city provides +100% Religious [ICON_Tourism] Tourism from this city. This city receives +1 [ICON_CULTURE] Culture and [ICON_FAITH] Faith from every 3 followers of your Religion. [NEWLINE][NEWLINE]Newly founded cities on all Tundra tiles gain +1 [ICON_CITIZEN] Population and a free Builder. +1 [ICON_Food] Food, +2 [ICON_PRODUCTION] Production, +1 [ICON_Culture] Culture and +1 [ICON_FAITH] Faith to Improvements on all Tundra tiles. Allows Farms to be built on Tundra terrain. After Civil Engineering is unlocked Farms can be built on Tundra Hills.[NEWLINE][NEWLINE]Must be built adjacent to a City Center, and you must have founded a Religion."),
    ("LOC_BUILDING_CHICHEN_ITZA_DESCRIPTION",                 "+1 Cultural policy slot. Your Cities yield +10% [ICON_Faith] Faith in [ICON_GLORY_GOLDEN_AGE] Golden Age, and +10% [ICON_Production] Production otherwise. +2 [ICON_CULTURE] Culture, +2 [ICON_FAITH] Faith for Holy Site, Campus, Theater Square and Entertainment Complex districts adjacent to Rainforest in your empire. Undamaged Land Combat units can be sacrificed on this tile, which gives Chichen Itza [ICON_CULTURE] Culture and [ICON_FAITH] Faith yield both equal to 25% of its base [ICON_STRENGTH] combat strength (rounded down and at least 1). Unit of a single type can only be sacrificed once. Must be built on Rainforest."),
    ("LOC_UNITCOMMAND_SACRIFICE_CHICHEN_ITZA_NAME",           "Sacrifice"),
    ("LOC_UNITCOMMAND_SACRIFICE_CHICHEN_ITZA_DESCRIPTION",    "Give Chichen Itza [ICON_CULTURE] Culture and [ICON_FAITH] Faith yield both equal to 25% of this unit's base [ICON_STRENGTH] combat strength (rounded down and at least 1)."),
    ("LOC_UNITCOMMAND_SACRIFICE_CHICHEN_ITZA_DISABLED_TT",    "Must be undamaged and be on Chichen Itza."),
    ("LOC_BUILDING_ORACLE_DESCRIPTION",                       "Patronage of Great People costs 25% less [ICON_Faith] Faith. +6 corresponding [ICON_GREATPERSON] Great Person Points for each Districts in this city. [NEWLINE][NEWLINE]Must be built on Hills or Mountains."),
    ("LOC_BUILDING_TEMPLE_ARTEMIS_DESCRIPTION",               "+2 [ICON_PRODUCTION] Production to your Commercial Hub and Entertainment Complex districts. For each type of Passable Features adjacent to this wonder, provide +1 [ICON_PRODUCTION] Production and [ICON_GOLD] Gold to these features in your empire. [NEWLINE][NEWLINE]Must be built adjacent to a Camp."),
    ("LOC_BUILDING_MAHABODHI_TEMPLE_EXPANSION2_DESCRIPTION",  "Grants 2 Apostles when built. Religious units ignore [ICON_MOVEMENT] movement penalty from Forest and Jungle. +100% [ICON_FAITH] Faith from buildings in Holy Site district with at least +6 adjacency bonus.[NEWLINE][NEWLINE]Must be built on Woods adjacent to a Holy Site district with a Tier 2 building, and you must have founded a Religion."),
    ("LOC_ABILITY_HD_MAHABODHI_TEMPLE_IGNORE_FOREST_DESCRIPTION","Ignore [ICON_MOVEMENT] movement penalty from Forest and Jungle."),
    ("LOC_BUILDING_ORSZAGHAZ_DESCRIPTION",                    "+2 Diplomatic Victory Points and +2 [ICON_ENVOY] Envoys when built. Doubles the effect of each Wildcard Policy in your government except the effect that grant ability to unit. Receive +100% [ICON_Favor] Diplomatic Favor per turn from starting a turn as Suzerain of a City-State.[NEWLINE][NEWLINE]Must be built next to a River."),
    ("LOC_BUILDING_STATUE_OF_ZEUS_DESCRIPTION",               "Monuments provide +1 Influence point per turn. Double bonus from Pantheon, except the effect that grant ability to unit. [NEWLINE][NEWLINE]Must be built adjacent to a Theater district. Must be built next to a River."),
    ("LOC_BUILDING_GREAT_LIBRARY_DESCRIPTION",                "Receive boosts to all Ancient and Classical era technologies. [ICON_TechBoosted] Eurekas provide +3% [ICON_SCIENCE] Science after finishing this Wonder (Ancient and Classical Techs excluded). Receive a random tech boost after another player recruits a [ICON_GreatScientist] Great Scientist. [NEWLINE][NEWLINE]Must be built on flat land adjacent to a Campus district with a Library."),
    ("LOC_BUILDING_GREAT_LIGHTHOUSE_DESCRIPTION",             "+1 [ICON_Movement] Movement for all Naval and Embarked units. Grants a free [ICON_GREATADMIRAL] Great Admiral. [NEWLINE][NEWLINE]Must be built on the Shallow Sea, and adjacent to land and a Harbor district with a Tier 1 building."),
    ("LOC_BUILDING_GREAT_ZIMBABWE_DESCRIPTION",               "+1 [ICON_TRADEROUTE] Trade Route capacity. Grants a Trader unit. Your International [ICON_TradeRoute] Trade Routes from this city and Domestic [ICON_TRADEROUTE] Trade Route to the city get +3 [ICON_Gold] Gold for every improved land Bonus resource in this city. [NEWLINE][NEWLINE] Must be built adjacent to a Commercial Hub district with a Tier 1 building and a Pasture."),
    ("LOC_BUILDING_BROADWAY_DESCRIPTION",                     "+30% [ICON_Culture] Culture in this city. Grants 1 free [ICON_GreatMusician] Great Musician. Citizens in Cities within 9 tiles provide +1 [ICON_Culture] Culture. When Broadway built, all [ICON_GreatWriter] Great Writers、 [ICON_GreatArtist] Great Artists、 [ICON_GreatMusician] Great Musicians provide +150 [ICON_GOLD] Gold and +25 [ICON_CULTURE] Culture.[NEWLINE][NEWLINE]Must be built on flat land adjacent to a Commercial Hub district(Has Stock Exchange)."),
    ("LOC_BUILDING_UNIVERSITY_SANKORE_DESCRIPTION",           "+5 [ICON_SCIENCE] Science and +1 [ICON_Faith] Faith to all your Cities within 6 tiles. +1 [ICON_SCIENCE] to all Desert tiles (Desert Floodplains excluded) in this City. Campus gain standard adjacency bonus from Desert and Desert Hill Tiles.[NEWLINE][NEWLINE]Must be built on Desert or Desert Hills adjacent to a Campus district with a University."),
    ("LOC_BUILDING_HAGIA_SOPHIA_DESCRIPTION",                 "Missionaries and Apostles can spread Religion 1 extra time. When you use a religious unit to convert a city for the first time, earn +10 [ICON_FAITH] Faith per [ICON_Citizen] Population of that city (on Standard Speed). When a holy city of another religion (if not occupied) converts to your religion, if your religion has a Worship Belief, your worship building can also have the effect of that religion's worship building (if present). [NEWLINE][NEWLINE]Must be built on flat land adjacent to a Holy Site district, and you must have founded a Religion."),
    ("LOC_BUILDING_BIOSPHERE_EXPANSION2_DESCRIPTION",         "Offshore Windfarms, Solar Farms, Wind Farms, Geothermal Plants, and Hydroelectric Dams provide +400% [ICON_POWER] Power. This building and these improvements provide [ICON_TOURISM] Tourism equal to their [ICON_POWER] Power. Rainforest and Marsh in your empire now provide +1 Appeal to adjacent tiles (rather than -1).[NEWLINE][NEWLINE]Must be built along a River adjacent to a Neighborhood district."),
    ("LOC_BUILDING_KOTOKU_IN_DESCRIPTION",                    "Grants a free [ICON_GREATWORK_RELIC] Relic when built. Coastal Cities receive +5% [ICON_PRODUCTION] Production, [ICON_CULTURE] Culture and [ICON_Faith] Faith and +2 [ICON_AMENITIES] Amenities. Each Worship Building provides +50% Religious and Wonder [ICON_TOURISM] Tourism from this city. [NEWLINE][NEWLINE]Must be built adjacent to Sea and adjacent to a Holy Site district with a Tier 2 building."),
    ("LOC_BUILDING_POTALA_PALACE_EXPANSION2_DESCRIPTION",     "+1 Diplomatic Victory point. After construction, if you do not create a religion and you have a major religion, your cities receive an additional bonus of Follower Belief of your major religion; if you already have a religion and adopts all beliefs, allow you to choose one additional Founder Belief and one additional Enchancer Belief for your religion. [NEWLINE][NEWLINE]Must be built on a Hill or a Mountain tile."),
    ("LOC_BUILDING_POTALA_PALACE_EXTRA_BELIEF_AVAILABLE",     "Allows to choose one additional Founder Belief and one additional Enchancer Belief."),
    
    ("LOC_BUILDING_HANGING_GARDENS_DESCRIPTION",              "+10% [ICON_FOOD] Food in all cities. Must be built next to a River."),
    ("LOC_BUILDING_JEBEL_BARKAL_EXPANSION2_DESCRIPTION",      "Provides 6 [ICON_RESOURCE_IRON] Iron per turn. +1 [ICON_CULTURE] Culture and +1 [ICON_FAITH] Faith to all districts built on Desert or Desert Hill terrain within 6 tiles. [NEWLINE][NEWLINE]Must be built on Desert Hill or Desert Mountain."),
    ("LOC_BUILDING_CRISTO_REDENTOR_DESCRIPTION",              "[ICON_Tourism] Tourism output from [ICON_GreatWork_Relic] Relics and Holy Cities is not diminished by other civilizations who have researched The Enlightenment civic. +100% [ICON_Tourism] Tourism from Seaside Resorts across your civilization. Patronage of Great People costs 25% less [ICON_Faith] Faith. [NEWLINE][NEWLINE]Must be built on a Hill or a Mountain tile."),
    ("LOC_BUILDING_HUEY_TEOCALLI_DESCRIPTION",                "+1 [ICON_Amenities] Amenity from each Lake tile within one tile of Huey Teocalli. +2 [ICON_Food] Food and +1 [ICON_Production] Production for plots, districts and wonders on or adjacent to lake in your empire. Must be built on a Lake tile adjacent to land."),
    ("LOC_BUILDING_MACHU_PICCHU_DESCRIPTION",                 "Mountain tiles provide a standard adjacency bonus to Commercial Hub, Theater Square, and Industrial Zone districts in all cities. All Districts (Wonders not included) adjacent to Mountain tiles provide +2 [ICON_FOOD] Food.[NEWLINE][NEWLINE]Must be built on a Mountain tile that does not contain a Volcano."),
    ("LOC_BUILDING_COLOSSUS_DESCRIPTION",                     "+1 [ICON_TradeRoute] Trade Route capacity. Grants a Trader unit. International trade routes from this City provide +2 [ICON_GOLD] Gold for each Fishing Boat owned by this City. [NEWLINE][NEWLINE]Must be built on the Shallow Sea, adjacent to a Harbor district."),
    ("LOC_BUILDING_TAJ_MAHAL_DESCRIPTION",                    "+1 Era Score from Historic Moment earned after this wonder is complete if that Moment is usually worth 2 or more Era Score. Your civilizaiton gets +5% [ICON_GREATENGINEER] Great Engineer Points for each wonder in this city. Each Wonder in this city provides +3 [ICON_CULTURE] Culture, +3 [ICON_FAITH] Faith. Wonders in your civilizaiton provides +100% [ICON_TOURISM] Tourism.[NEWLINE][NEWLINE]Must be built next to a River."),
    -- ("LOC_BUILDING_TAJ_MAHAL_DESCRIPTION",                    "+1 Era Score from Historic Moment earned after this wonder is complete if that Moment is usually worth 2 or more Era Score. +8 [ICON_GOLD] Gold for all world wonders in your empire. Each time you complete a wonder, gain [ICON_GOLD] Gold equal to 80% of its production cost.[NEWLINE][NEWLINE]Must be built next to a River."),
    ("LOC_BUILDING_TORRE_DE_BELEM_DESCRIPTION",               "International [ICON_TradeRoute] Trade Routes from this city receive +2 [ICON_GOLD] Gold for every Luxury resource at the destination. Grants two Settlers when built. Settlers have +2 [ICON_Movement] Movement. +2 starting [ICON_Citizen] Population for Cities settled on a different continent than your first City. [NEWLINE][NEWLINE]Must be built on a Shallow Sea tile adjacent to a Harbor district."),
    ("LOC_BUILDING_VENETIAN_ARSENAL_DESCRIPTION",             "Provide +6 [ICON_RESOURCE_Niter] Niter per turn. Shallow Sea and Lake tiles provide a standard adjacency bonus for Industrial Zone and Encampment districts. Receive a second naval unit each time you train a naval unit. [NEWLINE][NEWLINE]Must be built on a Shallow Sea tile that is adjacent to an Industrial Zone district."),
    ("LOC_DISTRICT_COAST_PRODUCTION_HD",                      "+{1_num} [ICON_Production] Production from the adjacent Shallow Sea and Lake {1_Num : plural 1?tile; other?tiles;}."),
    ("LOC_BUILDING_APADANA_DESCRIPTION",                      "+1 [ICON_ENVOY] Envoy each time you complete a wonder.[NEWLINE][NEWLINE]Must be built adjacent to your [ICON_CAPITAL] Capital."),
    ("LOC_BUILDING_ALHAMBRA_DESCRIPTION",                     "Double yields of buildings in City Center if city is built by you on a Breathtaking tile. +2 [ICON_Amenities] Amenities to Cities you captured and built on a Breathtaking tile. Provides the same defensive bonuses as the Fort improvement. [NEWLINE][NEWLINE]Must be built on Hills or Mountains."),
    ("LOC_BUILDING_CASA_DE_CONTRATACION_DESCRIPTION",         "Gain 3 [ICON_Governor] Governor titles. All your cities not on your original [ICON_Capital] Capital's continent with a [ICON_Governor] Governor gain +15% [ICON_Production] Production, +15% [ICON_Faith] Faith and +15% [ICON_Gold] Gold. [NEWLINE][NEWLINE]Must be built adjacent to a Harbor."),
    ("LOC_BUILDING_ESTADIO_DO_MARACANA_DESCRIPTION",          "Citizens working in specialty districts provide +4 corresponding yield. +50% [ICON_GREATPERSON] Great Person points in every City if this City is fully [ICON_POWER] Powered."),
    ("LOC_BUILDING_MARACANA_DUMMY_INTERNAL_ONLY_NAME",                 	"Having Estádio do Maracanã in your civilization"),
    ("LOC_BUILDING_MARACANA_DUMMY_DISTRICT_HOLY_SITE_NAME",                 "[COLOR:ResFaithLabelCS]Specialists yield bonus[ENDCOLOR]"),
    ("LOC_BUILDING_MARACANA_DUMMY_DISTRICT_HOLY_SITE_DESCRIPTION",          "Citizens working in this district provide +4 [Icon_Faith] Faith."),
    ("LOC_BUILDING_MARACANA_DUMMY_DISTRICT_CAMPUS_NAME",                    "[COLOR:ResScienceLabelCS]Specialists yield bonus[ENDCOLOR]"),
    ("LOC_BUILDING_MARACANA_DUMMY_DISTRICT_CAMPUS_DESCRIPTION",             "Citizens working in this district provide +4 [ICON_Science] Science."),
    ("LOC_BUILDING_MARACANA_DUMMY_DISTRICT_HARBOR_NAME",                    "[COLOR:ResGoldLabelCS]Specialists yield bonus[ENDCOLOR]"),
    ("LOC_BUILDING_MARACANA_DUMMY_DISTRICT_HARBOR_DESCRIPTION",             "Citizens working in this district provide +4 [ICON_Gold] Gold."),
    ("LOC_BUILDING_MARACANA_DUMMY_DISTRICT_ENCAMPMENT_NAME",                "[COLOR:ResProductionLabelCS]Specialists yield bonus[ENDCOLOR]"),
    ("LOC_BUILDING_MARACANA_DUMMY_DISTRICT_ENCAMPMENT_DESCRIPTION",         "Citizens working in this district provide +4 [ICON_Production] Production."),
    ("LOC_BUILDING_MARACANA_DUMMY_DISTRICT_COMMERCIAL_HUB_NAME",            "[COLOR:ResGoldLabelCS]Specialists yield bonus[ENDCOLOR]"),
    ("LOC_BUILDING_MARACANA_DUMMY_DISTRICT_COMMERCIAL_HUB_DESCRIPTION",     "Citizens working in this district provide +4 [ICON_Gold] Gold."),
    ("LOC_BUILDING_MARACANA_DUMMY_DISTRICT_THEATER_NAME",                   "[COLOR:ResCultureLabelCS]Specialists yield bonus[ENDCOLOR]"),
    ("LOC_BUILDING_MARACANA_DUMMY_DISTRICT_THEATER_DESCRIPTION",            "Citizens working in this district provide +4 [ICON_Culture] Culture."),
    ("LOC_BUILDING_MARACANA_DUMMY_DISTRICT_INDUSTRIAL_ZONE_NAME",           "[COLOR:ResProductionLabelCS]Specialists yield bonus[ENDCOLOR]"),
    ("LOC_BUILDING_MARACANA_DUMMY_DISTRICT_INDUSTRIAL_ZONE_DESCRIPTION",    "Citizens working in this district provide +4 [ICON_Production] Production."),
    ("LOC_BUILDING_MEENAKSHI_DUMMY_INTERNAL_ONLY_NAME",                	    "Having Meenakshi Temple in your civilization and Holy Site in this city"),
    ("LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_HOLY_SITE_NAME",                "[COLOR:ResFaithLabelCS]Specialists yield bonus[ENDCOLOR]"),
    ("LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_HOLY_SITE_DESCRIPTION",         "Meenakshi Temple gives it 1 extra citizen slot, and citizens working in this district provide +1 [Icon_Culture] Culture and +1 [Icon_Faith] Faith."),
    ("LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_CAMPUS_NAME",                   "[COLOR:ResScienceLabelCS]Specialists yield bonus[ENDCOLOR]"),
    ("LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_CAMPUS_DESCRIPTION",            "Meenakshi Temple gives it 1 extra citizen slot, and citizens working in this district provide +1 [Icon_Culture] Culture and +1 [Icon_Faith] Faith."),
    ("LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_HARBOR_NAME",                   "[COLOR:ResGoldLabelCS]Specialists yield bonus[ENDCOLOR]"),
    ("LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_HARBOR_DESCRIPTION",            "Meenakshi Temple gives it 1 extra citizen slot, and citizens working in this district provide +1 [Icon_Culture] Culture and +1 [Icon_Faith] Faith."),
    ("LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_ENCAMPMENT_NAME",               "[COLOR:ResProductionLabelCS]Specialists yield bonus[ENDCOLOR]"),
    ("LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_ENCAMPMENT_DESCRIPTION",        "Meenakshi Temple gives it 1 extra citizen slot, and citizens working in this district provide +1 [Icon_Culture] Culture and +1 [Icon_Faith] Faith."),
    ("LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_COMMERCIAL_HUB_NAME",           "[COLOR:ResGoldLabelCS]Specialists yield bonus[ENDCOLOR]"),
    ("LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_COMMERCIAL_HUB_DESCRIPTION",    "Meenakshi Temple gives it 1 extra citizen slot, and citizens working in this district provide +1 [Icon_Culture] Culture and +1 [Icon_Faith] Faith."),
    ("LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_THEATER_NAME",                  "[COLOR:ResCultureLabelCS]Specialists yield bonus[ENDCOLOR]"),
    ("LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_THEATER_DESCRIPTION",           "Meenakshi Temple gives it 1 extra citizen slot, and citizens working in this district provide +1 [Icon_Culture] Culture and +1 [Icon_Faith] Faith."),
    ("LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_INDUSTRIAL_ZONE_NAME",          "[COLOR:ResProductionLabelCS]Specialists yield bonus[ENDCOLOR]"),
    ("LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_INDUSTRIAL_ZONE_DESCRIPTION",   "Meenakshi Temple gives it 1 extra citizen slot, and citizens working in this district provide +1 [Icon_Culture] Culture and +1 [Icon_Faith] Faith."),
    ("LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_NEIGHBORHOOD_NAME",             "[COLOR:ResFoodLabelCS]Specialists yield bonus[ENDCOLOR]"),
    ("LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_NEIGHBORHOOD_DESCRIPTION",      "Meenakshi Temple gives it 1 extra citizen slot, and citizens working in this district provide +1 [Icon_Culture] Culture and +1 [Icon_Faith] Faith."),
    ("LOC_BUILDING_STATUE_LIBERTY_EXPANSION2_DESCRIPTION",                  "The first Harbor you build in each sea provides +1 [ICON_TRADEROUTE] Trade Route capacity. International [ICON_TRADEROUTE] Trade Routes gain +1 [ICON_GOLD] Gold for every Coast or Ocean tile in the origin city. [NEWLINE][NEWLINE]+4 Diplomatic Victory point. Open Borders with all city-states. Cure all naval units and promote them to a Fleet. Gain Influence Points per turn equal to 5% of base [ICON_STRENGTH] combat strength of all your military units garrisoned in the territory of city-states. [NEWLINE][NEWLINE]Must be built on a Shallow Sea tile, adjacent to a Harbor district and city must have Tier 3 Harbor building."),
	("LOC_BUILDING_BOLSHOI_THEATRE_DESCRIPTION",              			    "Awards 2 freely-chosen free civics when completed (to choose the Civic to be awarded, please click on the Civic icon on the Civic tree). [NEWLINE][NEWLINE]Must be built on flat land adjacent to a Theater Square district."),
	("LOC_UNCLOCK_FREE_CIVIC",            					  			    "Unlock this Civic.[NEWLINE]Can be used {1_Amount} more {1_Num : plural 1?time; other?times;}"),
    ("LOC_BUILDING_EIFFEL_TOWER_DESCRIPTION",                               "All tiles in your civilization gain +2 Appeal. Districts across your empire which built on tiles with at least 8 Appeal receive these bonuese: +50% adjacency bonus; provided [ICON_TOURISM] Tourism equal to the adjacency bonus; +15% accumulation rate for corresponding Great Person Points. Must be built on flat land adjacent to the City Center."),
    ("LOC_BUILDING_GOLDEN_GATE_BRIDGE_DESCRIPTION",                         "Every Wonder in this city provides +5 [ICON_GOLD] Gold to International [ICON_TRADEROUTE] Trade Route from the city and Domestic [ICON_TRADEROUTE] Trade Route to the city. All tiles in this city +4 Appeal. +100% [ICON_TOURISM] Tourism from improvements and National Parks in this city. [NEWLINE]Land units can cross without needing to embark. Acts as Modern Road and creates Modern Roads (if not present) in land tiles on either end. [ICON_TRADEROUTE] Trade Routes traveling through it can multiply the [ICON_GOLD] Gold they get from districts at their destination. [NEWLINE][NEWLINE]Must be built on a Shallow Sea tile. The bridge must run straight across the hex between two land tiles directly opposite one another. At least one water tile must be present on both the left and right sides of the bridge."),
    ("LOC_BUILDING_MONT_ST_MICHEL_DESCRIPTION",                             "Religious units ignore [ICON_MOVEMENT] Movement penalty from embarking, disembarking and crossing rivers and receive +2 [ICON_MOVEMENT] Movement if beginning on Coast or Ocean tiles. All Apostles you create gain the Martry and Pilgrim ability. If is first built by you, when you convert a city for the first time, earn 25 random [ICON_GREATPERSON] Great Person Points per [ICON_CITIZEN] Population of that city. [NEWLINE][NEWLINE]Must be built on Shallow Sea and Lake tiles adjacent to Land. Must have founded a Religion"),
    ("LOC_ABILITY_HD_MONT_ST_MICHEL_IGNORE_RIVER_DESCRIPTION",              "Ignore [ICON_MOVEMENT] Movement penalty from embarking, disembarking and crossing rivers.");
    
