-- Language: zh_Hans_CN
insert or replace into LocalizedText
    (Language,      Tag,                                                                                            Text)
values
    ("zh_Hans_CN",  "LOC_BUILDING_PETRA_NAME",                               "佩特拉卡兹尼神殿"),
    ("zh_Hans_CN",  "LOC_BUILDING_GREAT_BATH_DESCRIPTION",                   "可以使用 [ICON_FAITH] 信仰值购买水渠建筑。水渠建筑的产出+50%。[NEWLINE][NEWLINE]所在河流的泛滥平原单元格免受洪水侵袭带来的损害（但从洪水获得 [ICON_FOOD] 食物和 [ICON_PRODUCTION] 生产力加成的概率减半）。每次缓解洪水破坏后，属于此城市的泛滥平原单元格产出+1 [ICON_FAITH] 信仰值。[NEWLINE][NEWLINE]必须建在泛滥平原单元格中。"),
    ("zh_Hans_CN",  "LOC_BUILDING_MEENAKSHI_TEMPLE_DESCRIPTION",             "获得2名上师。拥有圣地的城市中，有专家槽位的区域+1专家槽位，且专家额外提供+1 [ICON_FOOD] 食物、+1 [ICON_CULTURE] 文化值、+1 [ICON_FAITH] 信仰值、-2 [ICON_GOLD] 金币。拥有圣地的城市+2 [ICON_HOUSING] 住房。拥有圣地的城市所有来自 [ICON_GreatWork_SCULPTURE] 艺术巨作的 [Icon_Tourism] 旅游业绩+50%。[NEWLINE][NEWLINE]必须建在圣地旁，同时必须已创立宗教。"), --圣地区域+2 [ICON_Food] 食物。
    ("zh_Hans_CN",  "LOC_BUILDING_PANAMA_CANAL_DESCRIPTION",                 "建成时市中心出现一位 [Icon_GreatMerchant] 大商人。开始修建巴拿马运河时，将在满足条件的相邻单元格自动开始建造1或2个运河，完成巴拿马运河的同时运河也将完成。建成的巴拿马运河将同样被视为运河。[NEWLINE]将巴拿马运河视为水域单元格时，必须有两个相邻巴拿马运河的且关于其对称的单元格满足：两个单元格均可以修建运河；或是一个单元格可以修建运河，一个单元格是城市/水域。如想使用巴拿马运河连接两座城市，那么这两座城市必须有至少一座相邻水域单元格或已经被运河连接至水域单元格。[NEWLINE]必须修建在平坦地形单元格之上。"),
    ("zh_Hans_CN",  "LOC_BUILDING_OXFORD_UNIVERSITY_DESCRIPTION",            "当前城市+20% [ICON_Science] 科技值，完成时，奖励2项当前可以研究的科技（点击科技树上的科技图标来选择被奖励的科技）。[NEWLINE]必须建在靠近带有大学的学院区域的平坦地形上。"),
    ("zh_Hans_CN",  "LOC_UNCLOCK_FREE_TECH",            					 "立刻完成该科技。[NEWLINE]还可以使用{1_Amount}次。"),
    ("zh_Hans_CN",  "LOC_BUILDING_KILWA_KISIWANI_DESCRIPTION",               "建成后+3 [ICON_ENVOY] 使者。对于每一类城邦，若你是其中至少1个的宗主国，本城中此类城邦对应的产出+15%；若你是其中至少2个的宗主国，本城中此类城邦对应的产出额外+15%。[NEWLINE][NEWLINE]必须建造在与沿海的平坦地形上。"),
    ("zh_Hans_CN",  "LOC_BUILDING_TERRACOTTA_ARMY_DESCRIPTION",              "目前所有单位获得1次强化等级。+1 军事政策槽位。[NEWLINE][NEWLINE]必须建在平坦的草原或平原上，且靠近建议一级建筑的军营区域。"),
    ("zh_Hans_CN",  "LOC_BUILDING_RUHR_VALLEY_DESCRIPTION",                  "每回合提供6点 [ICON_RESOURCE_COAL] 煤。该城市+15% [ICON_Production] 生产力。每个拥有工厂或电子厂的城市+5% [ICON_Production] 生产力并使玩家的 [ICON_GREATENGINEER] 大工程师点数积累速度+10%。[NEWLINE][NEWLINE]通往此城的国际 [ICON_TradeRoute] 贸易路线为双方+3 [ICON_PRODUCTION] 生产力。通往此城的国内 [ICON_TradeRoute] 贸易路线+6 [ICON_PRODUCTION] 生产力。[NEWLINE][NEWLINE]必须沿河而建，且与拥有二级建筑的工业区相邻。"),
    ("zh_Hans_CN",  "LOC_BUILDING_SYDNEY_OPERA_HOUSE_DESCRIPTION",           "建成时，获得一位免费的 [ICON_GreatMusician] 大音乐家。所有由玩家创立且有总督就职的城市中，来自奇观和巨作的 [Icon_Tourism] 旅游业绩+100%，其中来自 [ICON_GREATWORK_MUSIC] 音乐巨作的 [Icon_Tourism] 旅游业绩额外+100%。每回合额外获得等于 [Icon_Tourism] 境内旅游业绩50%的 [ICON_GOLD] 金币。[NEWLINE][NEWLINE]必须建在靠近陆地且相邻港口的浅海上。"),
    ("zh_Hans_CN",  "LOC_BUILDING_HERMITAGE_DESCRIPTION",                    "来自本城的艺术巨作的 [Icon_Tourism] 旅游业绩+200%。每招募1个大艺术家，获得等同于下一位 [ICON_GreatArtist] 大艺术家所需点数15%的所有类型的 [ICON_GreatPerson] 伟人点数。"),
    ("zh_Hans_CN",  "LOC_NOTIFIER_HERMITAGE_GPP",                            "{1_Amount}伟人点数从艾尔米塔什博物馆效果中获得!"),
    ("zh_Hans_CN",  "LOC_BUILDING_HERMITAGE_QUOTE",                          "真正的博物馆是把时间转化为空间的地方。[NEWLINE]——奥尔汗·帕慕克《纯真博物馆》"),
    ("zh_Hans_CN",  "LOC_BUILDING_FORBIDDEN_CITY_DESCRIPTION",               "+1 通配符政策槽位。[NEWLINE][NEWLINE]必须建在靠近市中心的平地上。"),
    ("zh_Hans_CN",  "LOC_BUILDING_PETRA_DESCRIPTION",                        "5个单元格内的所有沙漠单元格（非泛滥平原）+3 [ICON_Food] 食物、+1 [ICON_Production] 生产力和+2 [ICON_Gold] 金币。必须建在沙漠单元格（包括山脉和泛滥平原）。"),
    ("zh_Hans_CN",  "LOC_BUILDING_ST_BASILS_CATHEDRAL_NAME",                 "瓦西里升天教堂"),
    ("zh_Hans_CN",  "LOC_BUILDING_ST_BASILS_CATHEDRAL_DESCRIPTION",          "本城内每座奇观使本城产出的宗教 [ICON_Tourism] 旅游业绩+100%。你的宗教每有3个信徒，瓦西里升天教堂获得+1 [ICON_CULTURE] 文化值和 [ICON_FAITH] 信仰值。[NEWLINE][NEWLINE]在冻土或冻土丘陵单元格上新建立的城市+1 [ICON_CITIZEN] 市民并获得一个免费的建造者。改良的冻土或冻土丘陵单元格获得+1 [ICON_Food] 食物、+2 [ICON_PRODUCTION] 生产力、+1 [ICON_Culture] 文化值和+1 [ICON_FAITH] 信仰值。允许在冻土上建造农场。解锁“土木工程”后，即可在冻土丘陵上建造农场。[NEWLINE][NEWLINE]必须建在市中心旁，且玩家已创立宗教。"),
    ("zh_Hans_CN",  "LOC_BUILDING_CHICHEN_ITZA_DESCRIPTION",                 "+1文化政策槽位。处于 [ICON_GLORY_GOLDEN_AGE] 黄金时代时，所有城市+10% [ICON_Faith] 信仰值，处于 [ICON_GLORY_NORMAL_AGE] 非黄金时代时，所有城市+10% [ICON_Production] 生产力。您境内每个相邻雨林的圣地、学院、剧院广场和娱乐中心+2 [ICON_CULTURE] 文化值，+2 [ICON_FAITH] 信仰值。未受伤的陆地战斗单位可以在此单元格上被献祭，奇琴伊察获得等同于其基础 [ICON_STRENGTH] 战斗力25%（向下取整且至少为1）的 [ICON_CULTURE] 文化值和 [ICON_FAITH] 信仰值产出。每种单位只能献祭一次。[NEWLINE][NEWLINE]必须建在雨林上。"),
    ("zh_Hans_CN",  "LOC_UNITCOMMAND_SACRIFICE_CHICHEN_ITZA_NAME",           "献祭"),
    ("zh_Hans_CN",  "LOC_UNITCOMMAND_SACRIFICE_CHICHEN_ITZA_DESCRIPTION",    "给奇琴伊察等同于该单位基础 [ICON_STRENGTH] 战斗力25%（向下取整且至少为1）的 [ICON_CULTURE] 文化值和 [ICON_FAITH] 信仰值产出。"),
    ("zh_Hans_CN",  "LOC_UNITCOMMAND_SACRIFICE_CHICHEN_ITZA_DISABLED_TT",    "必须未受伤且位于奇琴伊察。"),
    ("zh_Hans_CN",  "LOC_BUILDING_ORACLE_DESCRIPTION",                       "伟人赞助消耗的 [ICON_Faith] 信仰值减少25%。本城的每个区域提供+6对应 [ICON_GreatPerson] 伟人点数。[NEWLINE][NEWLINE]必须建在丘陵或山脉单元格上。"),
    ("zh_Hans_CN",  "LOC_BUILDING_TEMPLE_ARTEMIS_DESCRIPTION",               "你的商业中心和娱乐中心+2 [ICON_Production] 生产力。对于与该奇观相邻的每种可通行地貌类型，境内的这些地貌上+1 [ICON_Production] 生产力和 [ICON_Gold] 金币。[NEWLINE][NEWLINE]必须建造在相邻营地的单元格上。"),
    ("zh_Hans_CN",  "LOC_BUILDING_MAHABODHI_TEMPLE_EXPANSION2_DESCRIPTION",  "建成后提供2个使徒。宗教单位无视森林和雨林对 [ICON_MOVEMENT] 移动力的减益。基础相邻加成至少+6的圣地建筑产出的 [ICON_FAITH] 信仰值+100%。[NEWLINE][NEWLINE]必须建在与建有二级建筑的圣地区域相邻的树林中，前提还须已创立宗教。"),
    ("zh_Hans_CN",  "LOC_ABILITY_HD_MAHABODHI_TEMPLE_IGNORE_FOREST_DESCRIPTION","菩提悟道：无视森林和雨林对 [ICON_MOVEMENT] 移动力的减益。"),
    ("zh_Hans_CN",  "LOC_BUILDING_ORSZAGHAZ_NAME",                           "匈牙利国会大厦"),
    ("zh_Hans_CN",  "LOC_BUILDING_ORSZAGHAZ_DESCRIPTION",                    "建成时+2外交胜利点数，+2 [ICON_ENVOY] 使者。政体中每张生效中的通配政策卡效果翻倍，但不包括给予单位能力的效果。成为一座城邦的宗主国后，每回合从此城邦获得的 [ICON_Favor] 外交支持+100%。[NEWLINE][NEWLINE]必须修建在河边。"),
    ("zh_Hans_CN",  "LOC_BUILDING_STATUE_OF_ZEUS_DESCRIPTION",               "每座纪念碑提供+1影响力点数。来自万神殿的收益翻倍，但不包括给予单位能力的效果。[NEWLINE][NEWLINE]必须建造在与剧院广场区域相邻且临近河流的单元格上。"),
    ("zh_Hans_CN",  "LOC_BUILDING_GREAT_LIBRARY_DESCRIPTION",                "所有远古和古典时代的科技均获得 [ICON_TechBoosted] 尤里卡。建成后，[ICON_TechBoosted] 尤里卡提供的 [ICON_SCIENCE] 科技值+3%（不包括建成时触发的远古古典 [ICON_TechBoosted] 尤里卡）。其他玩家招募 [ICON_GreatScientist] 大科学家时将随机获得1个 [ICON_TechBoosted] 尤里卡。[NEWLINE][NEWLINE]必须建在与学院区域（其中须建有图书馆）相邻的平坦地面上。"),
    ("zh_Hans_CN",  "LOC_BUILDING_GREAT_LIGHTHOUSE_DESCRIPTION",             "所有海军单位和海运单位+1 [ICON_Movement] 移动力。建成时市中心出现一位 [ICON_GREATADMIRAL] 海军统帅。[NEWLINE][NEWLINE]必须建在浅海上，且必须与陆地和已有一级建筑的港口相邻。"),
    ("zh_Hans_CN",  "LOC_BUILDING_GREAT_ZIMBABWE_DESCRIPTION",               "+1 [ICON_TRADEROUTE] 贸易路线容量。获得1个商人单位。此城市中每个已改良的陆地加成资源为以本城为目的地的国内 [ICON_TRADEROUTE] 贸易路线和从此城市出发的国际 [ICON_TradeRoute] 贸易路线+3 [ICON_Gold] 金币。[NEWLINE][NEWLINE]必须建在与建有一级建筑的商业中心区域和牧场相邻的单元格上。"),
    ("zh_Hans_CN",  "LOC_BUILDING_BROADWAY_DESCRIPTION",                     "为此城+30% [ICON_Culture] 文化值。建成时市中心出现一位 [ICON_GreatMusician] 大音乐家。9环内的城市每位 [ICON_Citizen] 市民+1 [ICON_Culture] 文化值。建造完成时，玩家每招募过一个 [ICON_GreatWriter] 大作家、 [ICON_GreatArtist] 大艺术家、 [ICON_GreatMusician] 大音乐家便获得150 [ICON_GOLD] 金币和25点 [ICON_CULTURE] 文化值。[NEWLINE][NEWLINE]必须建在邻近商业中心（拥有证券交易所）的平坦单元格上。"),
    ("zh_Hans_CN",  "LOC_BUILDING_UNIVERSITY_SANKORE_DESCRIPTION",           "为6个单元格内的所有城市提供+5 [ICON_SCIENCE] 科技值和 +1 [ICON_Faith] 信仰值。本城所有的除沙漠泛滥外的沙漠单元格+1 [ICON_SCIENCE] 科技值。 学院从沙漠和沙漠丘陵单元格获得标准相邻加成。[NEWLINE][NEWLINE]必须修建在沙漠或沙漠丘陵之上，同时必须与学院区域（其中须建有大学）相邻。"),
    ("zh_Hans_CN",  "LOC_BUILDING_HAGIA_SOPHIA_DESCRIPTION",                 "传教士和使徒可以额外传播一次宗教。利用宗教单位使城市首次改变信仰时，该城市每拥有1点 [ICON_Citizen] 人口，则提供10点 [ICON_FAITH] 信仰值（标准速度下）。当其他宗教的圣城（若未被占领）皈依您的宗教时，若你的宗教已有祭祀信仰，则您的祭祀建筑也能获得该宗教祭祀建筑（若存在）的效果。[NEWLINE][NEWLINE]您必须已经创立了一个宗教，必须建在靠近圣地的平坦地形上。"),
    ("zh_Hans_CN",  "LOC_BUILDING_BIOSPHERE_EXPANSION2_DESCRIPTION",         "所有离岸风力发电厂、太阳能农场、风力发电厂、地热发电厂和水电站坝产出的 [ICON_POWER] 电力+400%。此建筑和这些改良设置将提供等同于其 [ICON_POWER] 电力的 [ICON_TOURISM] 旅游业绩。境内与雨林和沼泽相邻的单元格+1魅力（而不是-1）。[NEWLINE][NEWLINE]必须建在与“社区”区域相邻的河流旁。"),
    ("zh_Hans_CN",  "LOC_BUILDING_KOTOKU_IN_DESCRIPTION",                    "建成时获得一个免费的 [ICON_GREATWORK_RELIC] 遗物。所有沿海城市+5% [ICON_PRODUCTION] 生产力、[ICON_CULTURE] 文化值和 [ICON_FAITH] 信仰，且+2 [ICON_AMENITIES] 宜居度。境内的每座祭祀建筑使本城来自宗教和奇观的 [ICON_TOURISM] 旅游业绩+50%。[NEWLINE][NEWLINE]必须建在沿海的单元格上，且必须相邻拥有二级建筑的圣地。"),
    ("zh_Hans_CN",  "LOC_BUILDING_POTALA_PALACE_EXPANSION2_DESCRIPTION",     "+1外交胜利点数。建成时，若你没有创立宗教且有主流宗教，则你的所有城市额外获得一份该主流宗教的信徒信仰的收益；若你已经创立宗教且已经纳入全部信仰，则允许为您的宗教额外选择一项创始人信仰和一项强化信仰。[NEWLINE][NEWLINE]必须建在丘陵或山脉单元格上。"),
    ("zh_Hans_CN",  "LOC_BUILDING_POTALA_PALACE_EXTRA_BELIEF_AVAILABLE",     "允许为您的宗教额外选择一项创始人信仰和一项强化信仰。"),
    ("zh_Hans_CN",  "LOC_BUILDING_HANGING_GARDENS_DESCRIPTION",              "所有城市+10% [ICON_FOOD] 食物。必须建在河流旁边。"),
    ("zh_Hans_CN",  "LOC_BUILDING_JEBEL_BARKAL_EXPANSION2_DESCRIPTION",      "每回合提供6点 [ICON_RESOURCE_IRON] 铁。6个单元格内建造在沙漠或沙漠丘陵单元格上的区域+1 [ICON_CULTURE] 文化值、+1 [ICON_FAITH] 信仰值。[NEWLINE][NEWLINE]必须建在沙漠丘陵或沙漠山脉上。"),
    ("zh_Hans_CN",  "LOC_BUILDING_CRISTO_REDENTOR_DESCRIPTION",              "[ICON_GreatWork_Relic] 遗物和圣城的 [ICON_Tourism] 旅游业绩产值不会被其他研究了“启蒙运动”市政的文明削弱。您文明中“海滨度假区”产出的 [ICON_Tourism] 旅游业绩+100%。伟人赞助消耗的 [ICON_Faith] 信仰值减少25%。[NEWLINE][NEWLINE]必须建在丘陵或山脉单元格上。"),
    ("zh_Hans_CN",  "LOC_BUILDING_HUEY_TEOCALLI_DESCRIPTION",                "在休伊神庙一个单元格以内的每个湖泊单元格为城市+1 [ICON_Amenities] 宜居度。为境内的每个相邻或位于湖泊的单元格、区域和奇观+2 [ICON_Food] 食物和+1 [ICON_Production] 生产力。[NEWLINE][NEWLINE]必须建在靠近陆地的湖泊单元格上。"),
    ("zh_Hans_CN",  "LOC_BUILDING_MACHU_PICCHU_DESCRIPTION",                 "山脉单元格为所有城市的商业中心、剧院广场及工业区提供标准的相邻加成。所有靠山的区域（不包含奇观）+2 [ICON_FOOD] 食物。[NEWLINE][NEWLINE]必须修建在无火山的山脉单元格中。"),
    ("zh_Hans_CN",  "LOC_BUILDING_COLOSSUS_DESCRIPTION",                     "+1 [ICON_TradeRoute] 贸易路线容量。获得1个商人单位。本城拥有的每个渔船为从该城出发的国际 [ICON_TRADEROUTE] 贸易路线+2 [ICON_GOLD] 金币。[NEWLINE][NEWLINE]必须建在邻近港口的浅海上。"),
    ("zh_Hans_CN",  "LOC_BUILDING_TAJ_MAHAL_DESCRIPTION",                    "此奇观建成后，提供2点或以上时代得分的历史时刻所提供的时代得分+1。本城内每座奇观使玩家 [ICON_GREATENGINEER] 大工程师点数累积速度+5%。本城每座奇观+3 [ICON_CULTURE] 文化值，+3 [ICON_Faith] 信仰值。全国奇观提供的 [ICON_TOURISM] 旅游业绩+100%。[NEWLINE][NEWLINE]必须建在河流旁。"),
    -- ("zh_Hans_CN",  "LOC_BUILDING_TAJ_MAHAL_DESCRIPTION",                    "此奇观建成后，提供2点或以上时代得分的历史时刻所提供的时代得分+1。所有世界奇观+8 [ICON_GOLD] 金币。完成世界奇观后返还等同于奇观所需产能80%的 [ICON_GOLD] 金币。[NEWLINE][NEWLINE]必须建在河流旁。"),
    ("zh_Hans_CN",  "LOC_BUILDING_TORRE_DE_BELEM_DESCRIPTION",               "目的地城市每有1处奢侈品资源，从此城起源的国际 [ICON_TradeRoute] 贸易路线便+2 [ICON_GOLD] 金币。建成时获得2个开拓者，所有开拓者+2 [ICON_Movement] 移动力。和首座城市不在同一个大陆上的城市+2初始 [ICON_Citizen] 人口。[NEWLINE][NEWLINE]必须建在邻近陆地和港口的浅海上。"), 
    ("zh_Hans_CN",  "LOC_BUILDING_VENETIAN_ARSENAL_DESCRIPTION",             "每回合提供6点 [ICON_RESOURCE_Niter] 硝石。浅海与湖泊单元格为工业区和军营提供标准相邻加成。每训练一个海军单位，便会获得第二个海军单位。[NEWLINE][NEWLINE]必须建在靠近工业区的浅海单元格上。"),
    ("zh_Hans_CN",  "LOC_DISTRICT_COAST_PRODUCTION_HD",                      "+{1_num} [ICON_Production] 生产力来自相邻的浅海与湖泊{1_Num : plural 1?单元格; other?单元格;}。"),
    ("zh_Hans_CN",  "LOC_BUILDING_APADANA_DESCRIPTION",                      "每建成1个奇观便获得1个 [ICON_ENVOY] 使者。[NEWLINE][NEWLINE]必须建造在 [ICON_CAPITAL] 首都旁。"),
    ("zh_Hans_CN",  "LOC_BUILDING_ALHAMBRA_DESCRIPTION",                     "您建立的位于惊艳单元格的城市市中心建筑的产出+100%。您占领的位于惊艳单元格的城市+2 [ICON_Amenities] 宜居度。提供与堡垒等同的防御加成。[NEWLINE][NEWLINE]必须建立在丘陵或山脉上。"),
    ("zh_Hans_CN",  "LOC_BUILDING_CASA_DE_CONTRATACION_DESCRIPTION",         "获得3次 [ICON_Governor] 总督升级。所有拥有 [ICON_Governor] 总督的异大陆城市 [ICON_Production] 生产力+15%、[ICON_Faith] 信仰值+15%、[ICON_Gold] 金币+15%。[NEWLINE][NEWLINE]必须建造在港口旁。"),
    ("zh_Hans_CN",  "LOC_BUILDING_ESTADIO_DO_MARACANA_DESCRIPTION",          "所有专业化区域专家额外+4对应产出。若此城 [ICON_POWER] 供电充足，则所有城市+50% [ICON_GreatPerson] 伟人点。[NEWLINE][NEWLINE]必须建造在相邻娱乐中心的平坦地形上，且本城必须建有体育场建筑。"),
    ("zh_Hans_CN",  "LOC_BUILDING_MARACANA_DUMMY_INTERNAL_ONLY_NAME",                  "拥有马拉卡纳体育场"),
    ("zh_Hans_CN",  "LOC_BUILDING_MARACANA_DUMMY_DISTRICT_HOLY_SITE_NAME",                 "[COLOR:ResFaithLabelCS]专家产出已提升[ENDCOLOR]"),
    ("zh_Hans_CN",  "LOC_BUILDING_MARACANA_DUMMY_DISTRICT_HOLY_SITE_DESCRIPTION",          "马拉卡纳体育场：专家额外+4 [Icon_Faith] 信仰值。"),
    ("zh_Hans_CN",  "LOC_BUILDING_MARACANA_DUMMY_DISTRICT_CAMPUS_NAME",                    "[COLOR:ResScienceLabelCS]专家产出已提升[ENDCOLOR]"),
    ("zh_Hans_CN",  "LOC_BUILDING_MARACANA_DUMMY_DISTRICT_CAMPUS_DESCRIPTION",             "马拉卡纳体育场：专家额外+4 [ICON_Science] 科技值。"),
