    ("zh_Hans_CN",  "LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_HOLY_SITE_NAME",                "[COLOR:ResFaithLabelCS]专家产出已提升[ENDCOLOR]"),
    ("zh_Hans_CN",  "LOC_BUILDING_MEENAKSHI_DUMMY_INTERNAL_ONLY_NAME",                     "拥有圣地且拥有米纳克希神庙"),
    ("zh_Hans_CN",  "LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_HOLY_SITE_DESCRIPTION",         "米纳克希神庙：提供+1专家槽位，且专家额外+1 [Icon_Culture] 文化值，+1 [Icon_Faith] 信仰值。"),
    ("zh_Hans_CN",  "LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_CAMPUS_NAME",                   "[COLOR:ResScienceLabelCS]专家产出已提升[ENDCOLOR]"),
    ("zh_Hans_CN",  "LOC_BUILDING_MEENAKSHI_DUMMY_DISTRICT_CAMPUS_DESCRIPTION",            "米纳克希神庙：提供+1专家槽位，且专家额外+1 [Icon_Culture] 文化值，+1 [Icon_Faith] 信仰值。"),
