-- Language: zh_Hans_CN
insert or replace into LocalizedText
    (Language,      Tag,                                                     Text)
values
    ("zh_Hans_CN",  "LOC_CL_NAT_WONDER_INTERNAL_NAME",                       "满足对应条件才能建造此"),

    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_COLLEGE_NAME",                        "国立学院"),
    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_COLLEGE_DESCRIPTION",                 "国家境内只能建造一座。必须建在与学院区域（其中须建有图书馆）相邻的平坦地形上。[NEWLINE][NEWLINE]获得1个 [ICON_GOVERNOR] 总督头衔。本城+100%学院相邻加成。玩家的 [ICON_GREATSCIENTIST] 大科学家点数积累速度+20%。[ICON_Governor] 总督在本城就职后，每次升级（包括首次升级）都将提供 +5% [ICON_Science] 科技值。"),
    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_COLLEGE_DESCRIPTION_INTERNAL",        "国家境内只能建造一座。必须建在与学院区域（其中须建有图书馆）相邻的平坦地形上。[NEWLINE][NEWLINE]获得1个 [ICON_GOVERNOR] 总督头衔。本城+100%学院相邻加成。玩家的 [ICON_GREATSCIENTIST] 大科学家点数积累速度+20%。[ICON_Governor] 总督在本城就职后，每次升级（包括首次升级）都将提供 +5% [ICON_Science] 科技值。"),
    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_COLLEGE_QUOTE",                       "教育并非为人生做准备，教育就是人生。[NEWLINE]——约翰·杜威"),
    ("zh_Hans_CN",  "LOC_PEDIA_NAT_WONDER_CL_COLLEGE_1",                     "国立高等院校通常是由政府创建或管理的高等教育中枢，其虽具官方属性，却可依据特定教育景观保持独立运作，不受国家直接管控。"),
    ("zh_Hans_CN",  "LOC_PEDIA_NAT_WONDER_CL_COLLEGE_2",                     "部分国立学府承载着民族文化或政治愿景，如爱尔兰国立大学；另一些则专为推进高等教育与学术研究而创立，如中国旨在建设世界一流大学的战略性联盟——九校联盟（C9联盟）。"),

    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_NATIONALEPIC_NAME",                   "民族史诗"),
    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_NATIONALEPIC_DESCRIPTION",            "国家境内只能建造一座。必须建在与剧院区域（其中须建有艺术博物馆或考古博物馆）相邻的陆地上。[NEWLINE][NEWLINE]此城+50% [ICON_GreatPerson] 伟人点。您的文明每获得1位 [ICON_GreatPerson] 伟人，民族史诗获得3份此 [ICON_GreatPerson] 伟人类型的对应产出（若是大作家 [ICON_GreatWriter] 、大艺术家 [ICON_GreatArtist] 、大音乐家 [ICON_GreatMusician] 则获得1份）。"),
    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_NATIONALEPIC_DESCRIPTION_INTERNAL",   "国家境内只能建造一座。必须建在与剧院区域（其中须建有艺术博物馆或考古博物馆）相邻的陆地上。[NEWLINE][NEWLINE]此城+50% [ICON_GreatPerson] 伟人点。您的文明每获得1位 [ICON_GreatPerson] 伟人，民族史诗获得3份此 [ICON_GreatPerson] 伟人类型的对应产出（若是大作家 [ICON_GreatWriter] 、大艺术家 [ICON_GreatArtist] 、大音乐家 [ICON_GreatMusician] 则获得1份）。"),
    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_NATIONALEPIC_QUOTE",                  "建筑艺术最伟大的作品，与其说是个人才华的产物，毋宁说是社会精神的凝结；与其说是天才灵光乍现，毋宁说是民族集体意志的结晶。[NEWLINE]——维克多·雨果"),
    ("zh_Hans_CN",  "LOC_PEDIA_NAT_WONDER_CL_NATIONALEPIC_1",                "自古以来，“民族史诗”是一种旨在捕捉与展现某个民族或国家精神内核的史诗体裁。这类史诗常以民族起源、重大历史事件或身份认同形成的关键节点为叙事核心。广义而言，民族史诗亦可指代使用民族语言创作、被该国人民或政府视为文化瑰宝的史诗作品。古希腊的《奥德赛》、美索不达米亚的《吉尔伽美什史诗》、古罗马的《埃涅阿斯纪》、印度的《摩诃婆罗多》、葡萄牙的《卢济塔尼亚人之歌》以及盎格鲁-撒克逊的《贝奥武夫》等，皆为民族史诗的典范之作。"),

    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_CITADEL_NAME",                        "大本营"),
    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_CITADEL_DESCRIPTION",                 "国家境内只能建造一座。解锁条件：与其他文明交战。必须建在与军营相邻的陆地上。[NEWLINE][NEWLINE]+1 军事政策槽位。提供与堡垒等同的防御加成。本城中立刻建造远古城墙和中世纪城墙。升级单位不会结束其回合，位于国境内的单位+4 [ICON_Strength] 战斗力。所有军营建筑+2 [ICON_Production] 生产力、+2 [ICON_Culture] 文化值。+100%军营相邻加成。军事工程师+1 [ICON_MOVEMENT] 移动力，+1建造次数。"),
    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_CITADEL_DESCRIPTION_INTERNAL",        "国家境内只能建造一座。[COLOR:Red]解锁条件：与其他文明交战。[ENDCOLOR]必须建在与军营相邻的陆地上。[NEWLINE][NEWLINE]+1 军事政策槽位。提供与堡垒等同的防御加成。本城中立刻建造远古城墙和中世纪城墙。升级单位不会结束其回合，位于国境内的单位+4 [ICON_Strength] 战斗力。所有军营建筑+2 [ICON_Production] 生产力、+2 [ICON_Culture] 文化值。+100%军营相邻加成。军事工程师+1 [ICON_MOVEMENT] 移动力，+1建造次数。"),
    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_CITADEL_QUOTE",                       "故用兵之法，无恃其不来，恃吾有以待也；无恃其不攻，恃吾有所不可攻也。[NEWLINE]——《孙子兵法》"),
    ("zh_Hans_CN",  "LOC_PEDIA_NAT_WONDER_CL_CITADEL_1",                     "城堡要塞特指依托城防体系构建的核心堡垒，其设计融合棱堡与护城河系统，常占据战略要地以抵御敌军对炮台阵地的持续进攻。该词源自意大利语'cittadella'（'城市'的指小形式）。"),
    ("zh_Hans_CN",  "LOC_PEDIA_NAT_WONDER_CL_CITADEL_2",                     "不同文明对此类建筑有特定称谓：俄罗斯称克里姆林，西班牙称阿卡萨。欧洲语境中“城堡要塞”与“城市堡垒”常互为代称，特殊案例则采用“塔”命名（如伦敦塔、耶路撒冷大卫塔）。西半球现存规模最大的城堡要塞为海地的拉费里埃城堡。"),

    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_TEMPLE_NAME",                         "圣殿"),
    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_TEMPLE_DESCRIPTION",                  "国家境内只能建造一座。解锁条件：已创立一个宗教，且至少有3座城市皈依您文明的宗教。必须建在与圣地相邻的陆地上。[NEWLINE][NEWLINE]本城的 [ICON_GREATWORK_RELIC] 遗物+2 [ICON_SCIENCE] 科技值和 [ICON_CULTURE] 文化值。每座信奉您的宗教的其他文明的城市使此城市中 [ICON_GREATWORK_RELIC] 遗物产出的 [ICON_TOURISM] 旅游业绩+30%；若为其他文明的 [ICON_CAPITAL] 首都，则额外+30%。"),
    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_TEMPLE_DESCRIPTION_INTERNAL",         "国家境内只能建造一座。[COLOR:Red]解锁条件：已创立一个宗教，且至少有3座城市皈依您文明的宗教。[ENDCOLOR]必须建在与圣地相邻的陆地上。[NEWLINE][NEWLINE]本城的 [ICON_GREATWORK_RELIC] 遗物+2 [ICON_SCIENCE] 科技值和 [ICON_CULTURE] 文化值。每座信奉您的宗教的其他文明的城市使此城市中 [ICON_GREATWORK_RELIC] 遗物产出的 [ICON_TOURISM] 旅游业绩+30%；若为其他文明的 [ICON_CAPITAL] 首都，则额外+30%。"),
    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_TEMPLE_QUOTE",                        "我曾在寺庙、教堂和清真寺中寻找，却在我的心中寻得了神性。[NEWLINE]——鲁米"),
    ("zh_Hans_CN",  "LOC_PEDIA_NAT_WONDER_CL_TEMPLE_1",                      "圣殿，作为特定信仰群体膜拜的神圣场域，往往以恢弘建筑与华美碑铭承载信众的精神寄托，其存续数个世纪的壮丽形制本身即成为宗教虔信的实体丰碑。纵览当今寰宇星罗棋布的宗教建筑遗存，虽学界对“最古老圣殿”尚无定论，但土耳其境内发现的哥贝克力石阵（Göbekli Tepe）——这座约1.2万年前由新石器时代先民构筑的巨石建筑群——仍被普遍视为人类迄今探明的最早期宗教性人造空间。"),

    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_THEMEPARK_NAME",                      "国家主题公园"),
    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_THEMEPARK_DESCRIPTION",               "国家境内只能建造一座。解锁条件：拥有4座建有娱乐中心或水上乐园的城市。必须建在与娱乐中心相邻的平坦地形上。[NEWLINE][NEWLINE]相邻奇观的娱乐中心或水上乐园为城市+10% [ICON_CULTURE] 文化值和 [ICON_GOLD] 金币。娱乐中心、水上乐园以及其中的每个建筑为所在城市奇观的 [ICON_Tourism] 旅游业绩+100%。拥有动物园的城市，牧场、营地、种植园和伐木场改良设施产出的 [ICON_Tourism] 旅游业绩+50%；拥有水族馆的城市，渔船改良设施产出的 [ICON_Tourism] 旅游业绩+50%。"),
    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_THEMEPARK_DESCRIPTION_INTERNAL",      "国家境内只能建造一座。[COLOR:Red]解锁条件：拥有4座建有娱乐中心或水上乐园的城市。[ENDCOLOR]必须建在与娱乐中心相邻的平坦地形上。[NEWLINE][NEWLINE]相邻奇观的娱乐中心或水上乐园为城市+10% [ICON_CULTURE] 文化值和 [ICON_GOLD] 金币。娱乐中心、水上乐园以及其中的每个建筑为所在城市奇观的 [ICON_Tourism] 旅游业绩+100%。拥有动物园的城市，牧场、营地、种植园和伐木场改良设施产出的 [ICON_Tourism] 旅游业绩+50%；拥有水族馆的城市，渔船改良设施产出的 [ICON_Tourism] 旅游业绩+50%。"),
    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_THEMEPARK_QUOTE",                     "在这里，你将拜访昨日、明日与幻想的世界。[NEWLINE]——沃尔特·迪士尼"),
    ("zh_Hans_CN",  "LOC_PEDIA_NAT_WONDER_CL_THEMEPARK_1",                   "主题公园是一种以核心主题为中心，集娱乐景点、游乐设施及其他类似结构于一体的综合性娱乐场所。相较于普通的城市公园或游乐场，主题公园的规划更为复杂，通常既提供专为特定年龄群体设计的游乐项目，也包含适合全年龄段参与的多样化体验。"),
    ("zh_Hans_CN",  "LOC_PEDIA_NAT_WONDER_CL_THEMEPARK_2",                   "主题公园的起源可追溯至欧洲集市与休闲花园，这些场所最初即为娱乐目的而建。全球现存最古老的主题公园是位于丹麦哥本哈根以北的巴肯公园，其历史可追溯至1583年。而加利福尼亚州阿纳海姆市的迪士尼乐园则保持着最高客流量记录，自开园以来已接待超过6亿游客。"),

    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_IRONWORKS_NAME",                      "大铁厂"),
    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_IRONWORKS_DESCRIPTION",               "国家境内只能建造一座。解锁条件：国家境内拥有至少4个战略资源的改良设施。必须建在工业区旁。[NEWLINE][NEWLINE]本城每拥有一种矿山或采石场改良的加成资源，为9个单元格之内的城市提供+2 [ICON_Production] 生产力和+2 [ICON_GREATENGINEER] 大工程师点数。本城每拥有一种改良的战略资源，为9个单元格之内的城市提供+2 [ICON_Science] 科技值和+2 [ICON_GREATSCIENTIST] 大科学家点数。"),
    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_IRONWORKS_DESCRIPTION_INTERNAL",      "国家境内只能建造一座。[COLOR:Red]解锁条件：国家境内拥有至少4个战略资源的改良设施。[ENDCOLOR]必须建在工业区旁。[NEWLINE][NEWLINE]本城每拥有一种矿山或采石场改良的加成资源，为9个单元格之内的城市提供+2 [ICON_Production] 生产力和+2 [ICON_GREATENGINEER] 大工程师点数。本城每拥有一种改良的战略资源，为9个单元格之内的城市提供+2 [ICON_Science] 科技值和+2 [ICON_GREATSCIENTIST] 大科学家点数。"),
    ("zh_Hans_CN",  "LOC_NAT_WONDER_CL_IRONWORKS_QUOTE",                     "不要等到铁热了才敲打，而是通过敲打使其变热。[NEWLINE]——威廉·巴特勒·叶芝"),
    ("zh_Hans_CN",  "LOC_PEDIA_NAT_WONDER_CL_IRONWORKS_1",                   "大铁厂是将铁矿石冶炼提纯并加工成铁或钢的工业设施。其工艺流程始于对原料进行高温熔炼，通过添加辅料最终获得精炼金属。铁器冶炼史至少可追溯至公元前1200年，甚或更早。此类工厂属高危作业环境，因而需要体魄强健、技艺精湛且胆识过人的产业工人。"),

    ("zh_Hans_CN",  "LOC_NAT_WON_CL_FINANCE_NAME",                           "金融中心"),
    ("zh_Hans_CN",  "LOC_NAT_WON_CL_FINANCE_DESCRIPTION",                    "国家境内只能建造一座。解锁条件：经营8条贸易路线。必须建在与商业中心相邻的陆地上。[NEWLINE][NEWLINE]本城+100%商业中心相邻加成。从拥有银行的城市出发的国际 [ICON_TradeRoute] 贸易路线+2 [ICON_Gold] 金币，从拥有证券交易所的城市出发的国际 [ICON_TradeRoute] 贸易路线+4 [ICON_Gold] 金币。 [ICON_GreatPerson] 伟人赞助消耗的 [ICON_Gold] 金币减少50%。"),
    ("zh_Hans_CN",  "LOC_NAT_WON_CL_FINANCE_DESCRIPTION_INTERNAL",           "国家境内只能建造一座。[COLOR:Red]解锁条件：经营8条贸易路线。[ENDCOLOR]必须建在与商业中心相邻的陆地上。[NEWLINE][NEWLINE]本城+100%商业中心相邻加成。从拥有银行的城市出发的国际 [ICON_TradeRoute] 贸易路线+2 [ICON_Gold] 金币，从拥有证券交易所的城市出发的国际 [ICON_TradeRoute] 贸易路线+4 [ICON_Gold] 金币。 [ICON_GreatPerson] 伟人赞助消耗的 [ICON_Gold] 金币减少50%。"),
    ("zh_Hans_CN",  "LOC_NAT_WON_CL_FINANCE_CORP_DESCRIPTION",               "国家境内只能建造一座。解锁条件：经营8条贸易路线。必须建在与公司相邻的陆地上。[NEWLINE][NEWLINE][ICON_GreatPerson] 伟人赞助消耗的 [ICON_Gold] 金币减少50%。拥有公司的城市+20% [ICON_Gold] 金币。国家境内的“公司”改良设施产出的 [ICON_Tourism] 旅游业绩+200%。拥有证券交易所的城市 [ICON_GreatWork_Product] 产品的产出翻倍。"),
    ("zh_Hans_CN",  "LOC_NAT_WON_CL_FINANCE_CORP_DESCRIPTION_INTERNAL",      "国家境内只能建造一座。[COLOR:Red]解锁条件：经营8条贸易路线。[ENDCOLOR]必须建在与公司相邻的陆地上。[NEWLINE][NEWLINE][ICON_GreatPerson] 伟人赞助消耗的 [ICON_Gold] 金币减少50%。拥有公司的城市+20% [ICON_Gold] 金币。国家境内的“公司”改良设施产出的 [ICON_Tourism] 旅游业绩+200%。拥有证券交易所的城市 [ICON_GreatWork_Product] 产品的产出翻倍。"),
    ("zh_Hans_CN",  "LOC_NAT_WON_CL_FINANCE_QUOTE",                          "当然，我讨厌百万富翁，不过如果把这种位置给我，那危险的就是其他人。[NEWLINE]——马克·吐温"),
    ("zh_Hans_CN",  "LOC_PEDIA_NAT_WON_CL_FINANCE_1",                        "金融中心指集聚银行、资管、保险及金融市场参与方的枢纽地带，配备专属交易场所与配套服务体系。参与主体涵盖三大类：银行与经纪商等金融中介；投资管理公司、保险机构及对冲基金等机构投资者；以及企业与政府等发行方。交易活动依托交易所等平台开展，并由清算所确保支付、证券及衍生品交易的结算监督。"),
    ("zh_Hans_CN",  "LOC_PEDIA_NAT_WON_CL_FINANCE_2",                        "国际货币基金组织将主要金融中心划分为三类：纽约、伦敦等全球金融中心；上海、法兰克福等区域金融中心；以及专注税务优化服务的离岸金融中心（如开曼群岛、都柏林、新加坡）。后者常被视为避税天堂的代名词。"),

    ("zh_Hans_CN",  "LOC_GOSSIP_SOURCE_NAT_AIRPORT",                         "国际机场的空姐获悉"),
    ("zh_Hans_CN",  "LOC_VIZSOURCE_NAT_AIRPORT",                             "建造了国际机场"),
    ("zh_Hans_CN",  "LOC_VIZSOURCE_ACTION_NAT_AIRPORT",                      "建造国际机场"),
    ("zh_Hans_CN",  "LOC_NAT_WON_CL_AIRPORT_NAME",                           "国际机场"),
    ("zh_Hans_CN",  "LOC_HD_NAT_AIRPORT_CORP_ADD",                           ""),
    ("zh_Hans_CN",  "LOC_NAT_WON_CL_AIRPORT_DESCRIPTION",                    "国家境内只能建造一座。必须建在平坦地形上。[NEWLINE][NEWLINE]{LOC_HD_NAT_AIRPORT_CORP_ADD}+3 [ICON_TradeRoute] 贸易路线容量。对所有文明+1 [ICON_VISLIMITED] 外交能见度。拥有机场（包括国际机场）的城市中的由飞行科技解锁旅游业绩产出的改良设施产出的 [ICON_Tourism] 旅游业绩+100%。对于每一条 [ICON_TradeRoute] 贸易路线连接，无论您的城市作为国际 [ICON_TradeRoute] 贸易路线的起点还是终点，您都可从该城内的专业化区域获得其作为国际目的地时的加成；若城市拥有机场（包括国际机场），则该效果翻倍。"),
    ("zh_Hans_CN",  "LOC_NAT_WON_CL_AIRPORT_DESCRIPTION_INTERNAL",           "国家境内只能建造一座。必须建在平坦地形上。[NEWLINE][NEWLINE]{LOC_HD_NAT_AIRPORT_CORP_ADD}+3 [ICON_TradeRoute] 贸易路线容量。对所有文明+1 [ICON_VISLIMITED] 外交能见度。拥有机场（包括国际机场）的城市中的由飞行科技解锁旅游业绩产出的改良设施产出的 [ICON_Tourism] 旅游业绩+100%。对于每一条 [ICON_TradeRoute] 贸易路线连接，无论您的城市作为国际 [ICON_TradeRoute] 贸易路线的起点还是终点，您都可从该城内的专业化区域获得其作为国际目的地时的加成；若城市拥有机场（包括国际机场），则该效果翻倍。"),
    ("zh_Hans_CN",  "LOC_NAT_WON_CL_AIRPORT_QUOTE",                          "世间语言竟无一种能造出‘美若机场’这等比喻——这绝非偶然。[NEWLINE]——道格拉斯·亚当斯"),
    ("zh_Hans_CN",  "LOC_PEDIA_NAT_WON_CL_AIRPORT_1",                        "国际航站楼是机场内设有海关与边检设施的功能区，专司跨境旅客通关之职。国际机场规模通常远超纯国内机场，其跑道更长、设施更优，以满足洲际航线常用大型客机的起降需求。"),
    ("zh_Hans_CN",  "LOC_PEDIA_NAT_WON_CL_AIRPORT_2",                        "1919年，伦敦豪恩斯洛希思机场首开全球定期国际商业航班先河。此后百年间，国际机场渐成大都市标配。当今全球最大国际航站楼坐落于北京大兴国际机场，其面积逾750万平方英尺（约合70万平方米），相当于98个标准足球场之巨！");